    async fn next_message(&self) -> anyhow::Result<Option<Arc<Vec<u8>>>>;
    /// Instructs the room to establish gossip relay to additional peers.
    async fn join_peers(&self, peers: Vec<NodeId>) -> anyhow::Result<()>;
